#!/usr/bin/perl
use strict;
use warnings;
use DBI;
use Config::Simple;
use Carp qw(croak);

# Load database credentials from external configuration file
# The config file should be stored outside the web root with restricted permissions
# (chmod 600, owned by the application user)
my $config_file = $ENV{'LEGACY_DB_CONFIG'} || '/etc/legacy_app/db.conf';

if (! -e $config_file) {
    croak "Database configuration file not found: $config_file\n"
        . "Please create the config file with the following format:\n"
        . "  db_dsn = DBI:mysql:database=legacy_db;host=localhost\n"
        . "  db_user = <username>\n"
        . "  db_pass = <password>\n";
}

# Verify config file permissions are restrictive (owner read/write only)
my $file_mode = (stat($config_file))[2] & 07777;
if ($file_mode & 0077) {
    croak sprintf(
        "Configuration file %s has insecure permissions (%04o). "
        . "Please set permissions to 0600: chmod 600 %s\n",
        $config_file, $file_mode, $config_file
    );
}

my $cfg = Config::Simple->new($config_file)
    or croak "Cannot read configuration file: " . Config::Simple->error();

my $db_dsn  = $cfg->param('db_dsn')
    or croak "Missing 'db_dsn' in configuration file";
my $db_user = $cfg->param('db_user')
    or croak "Missing 'db_user' in configuration file";
my $db_pass = $cfg->param('db_pass');

if (!defined $db_pass || $db_pass eq '') {
    croak "Missing 'db_pass' in configuration file";
