    $db_user,
    $db_pass,
    {
        RaiseError        => 1,
        AutoCommit        => 1,
        PrintError        => 0,
        mysql_enable_utf8 => 1,
        mysql_auto_reconnect => 0,  # Avoid silent reconnects in production
    }
) or croak "Database connection failed: " . DBI->errstr;

